'use client'

import { useEffect, useState } from 'react'
import Link from 'next/link'
import { useParams, useRouter } from 'next/navigation'
import { EditProjectModal } from '@/components/EditProjectModal'
import { DesignDocumentModal } from '@/components/DesignDocumentModal'
import { MarkdownRenderer } from '@/components/MarkdownRenderer'
import { StoriesTab } from '@/components/StoriesTab'

interface Project {
  id: string
  name: string
  slug: string
  description: string
  ownerId: string
  createdAt: string
  updatedAt: string
}

export default function ProjectDetailPage() {
  const params = useParams()
  const router = useRouter()
  const slug = params.slug as string
  const [project, setProject] = useState<Project | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [editModalOpen, setEditModalOpen] = useState(false)
  const [designDocModalOpen, setDesignDocModalOpen] = useState(false)
  const [activeTab, setActiveTab] = useState<'notes' | 'design-doc' | 'stories'>('notes')
  const [designDocContent, setDesignDocContent] = useState<string>('')
  const [isEditingDesignDoc, setIsEditingDesignDoc] = useState(false)

  useEffect(() => {
    loadProject()
  }, [slug])

  const loadProject = async () => {
    try {
      const response = await fetch('/api/projects')
      if (response.ok) {
        const projects = await response.json()
        const found = projects.find((p: Project) => p.slug === slug)
        if (found) {
          setProject(found)
        } else {
          setError('Project not found')
        }
      }
    } catch (err) {
      setError('Failed to load project')
    } finally {
      setLoading(false)
    }
  }

  const handleDelete = async () => {
    if (!project) return
    if (!confirm('Are you sure you want to delete this project?')) return

    try {
      const response = await fetch(`/api/projects/${project.id}`, {
        method: 'DELETE',
      })
      if (response.ok) {
        router.push('/projects')
      }
    } catch (err) {
      alert('Failed to delete project')
    }
  }

  if (loading) {
    return (
      <div className="text-center py-12">
        <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
        <p className="text-slate-400 mt-2">Loading project...</p>
      </div>
    )
  }

  if (error || !project) {
    return (
      <div className="space-y-6">
        <Link href="/projects" className="text-blue-400 hover:underline">
          ← Back to Projects
        </Link>
        <div className="border border-red-700 rounded-2xl p-8 text-center bg-red-900/30">
          <p className="text-red-400">{error || 'Project not found'}</p>
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-8">
      {/* Header */}
      <div>
        <Link href="/projects" className="text-blue-400 hover:underline mb-4 inline-block">
          ← Back to Projects
        </Link>
        <h1 className="text-4xl font-bold text-white mt-2">{project.name}</h1>
        {project.description && (
          <p className="text-slate-400 mt-2">{project.description}</p>
        )}
      </div>

      {/* Info Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6">
          <p className="text-slate-400 text-sm mb-1">Project ID</p>
          <p className="text-white font-mono text-sm break-all">{project.id}</p>
        </div>

        <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6">
          <p className="text-slate-400 text-sm mb-1">Slug</p>
          <p className="text-white font-mono">{project.slug}</p>
        </div>

        <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6">
          <p className="text-slate-400 text-sm mb-1">Created</p>
          <p className="text-white">{new Date(project.createdAt).toLocaleDateString()}</p>
        </div>

        <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6">
          <p className="text-slate-400 text-sm mb-1">Last Updated</p>
          <p className="text-white">{new Date(project.updatedAt).toLocaleDateString()}</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="space-y-6">
        <div className="flex gap-4 border-b border-slate-700">
          <button
            onClick={() => setActiveTab('notes')}
            className={`px-6 py-3 font-semibold transition-colors ${
              activeTab === 'notes'
                ? 'text-blue-400 border-b-2 border-blue-400'
                : 'text-slate-400 hover:text-slate-300'
            }`}
          >
             Notes
          </button>
          <button
            onClick={() => setActiveTab('design-doc')}
            className={`px-6 py-3 font-semibold transition-colors ${
              activeTab === 'design-doc'
                ? 'text-blue-400 border-b-2 border-blue-400'
                : 'text-slate-400 hover:text-slate-300'
            }`}
          >
             Design Doc
          </button>
          <button
            onClick={() => setActiveTab('stories')}
            className={`px-6 py-3 font-semibold transition-colors ${
              activeTab === 'stories'
                ? 'text-blue-400 border-b-2 border-blue-400'
                : 'text-slate-400 hover:text-slate-300'
            }`}
          >
             Stories
          </button>
        </div>

        {/* Tab Content */}
        {activeTab === 'notes' && (
          <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6 min-h-96">
            <h3 className="text-xl font-bold text-white mb-4">Project Notes</h3>
            <p className="text-slate-400">
              Project notes will appear here. You can add notes about this project.
            </p>
          </div>
        )}

        {activeTab === 'design-doc' && (
          <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6 min-h-96">
            {designDocContent ? (
              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <h3 className="text-xl font-bold text-white">Project Design Document</h3>
                  <div className="flex gap-2">
                    <button
                      onClick={() => setIsEditingDesignDoc(!isEditingDesignDoc)}
                      className={`px-4 py-2 rounded-lg transition-colors font-medium ${
                        isEditingDesignDoc
                          ? 'bg-green-600 hover:bg-green-700 text-white'
                          : 'bg-slate-700 hover:bg-slate-600 text-white'
                      }`}
                    >
                      {isEditingDesignDoc ? '✓ Done Editing' : '✏️ Edit'}
                    </button>
                    <button
                      onClick={() => setDesignDocModalOpen(true)}
                      className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium"
                    >
                       Regenerate
                    </button>
                  </div>
                </div>

                {isEditingDesignDoc ? (
                  <textarea
                    value={designDocContent}
                    onChange={(e) => setDesignDocContent(e.target.value)}
                    className="w-full h-96 px-4 py-3 bg-slate-900 border border-slate-600 rounded-lg text-white font-mono text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                ) : (
                  <div className="bg-slate-900 border border-slate-700 rounded-lg p-4 overflow-auto max-h-96 text-slate-300 text-sm">
                    <MarkdownRenderer content={designDocContent} />
                  </div>
                )}
              </div>
            ) : (
              <div className="text-center py-8">
                <div className="text-4xl mb-4"></div>
                <h3 className="text-lg font-semibold text-white mb-2">No Design Document</h3>
                <p className="text-slate-400 mb-6">Generate a design document to get started</p>
                <button
                  onClick={() => setDesignDocModalOpen(true)}
                  className="px-6 py-2 bg-gradient-to-r from-purple-600 to-purple-700 text-white font-medium rounded-full hover:from-purple-500 hover:to-purple-600 transition-colors"
                >
                   Generate Design Doc
                </button>
              </div>
            )}
          </div>
        )}

        {activeTab === 'stories' && (
          <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6 min-h-96">
            <StoriesTab
              projectId={project.id}
              designDocContent={designDocContent}
              onStoriesGenerated={(stories) => {
                // Stories generated callback
              }}
            />
          </div>
        )}
      </div>

        {/* Actions */}
        <div className="space-y-4">
          <h2 className="text-2xl font-bold text-white">Actions</h2>
          <div className="flex gap-4 flex-wrap">
            <button
              onClick={() => setEditModalOpen(true)}
              className="px-6 py-2.5 bg-blue-600 text-white font-medium rounded-full hover:bg-blue-700 transition-colors"
            >
              ✏️ Edit Project
            </button>
            <button
              onClick={handleDelete}
              className="px-6 py-2.5 border border-red-700 text-red-400 font-medium rounded-full hover:bg-red-900/20 transition-colors"
            >
              ️ Delete Project
            </button>
          </div>
        </div>

       {/* Edit Modal */}
       <EditProjectModal
         isOpen={editModalOpen}
         projectId={project.id}
         projectName={project.name}
         projectDescription={project.description}
         onClose={() => setEditModalOpen(false)}
         onSuccess={() => loadProject()}
       />

       {/* Design Document Modal */}
       <DesignDocumentModal
         isOpen={designDocModalOpen}
         onClose={() => setDesignDocModalOpen(false)}
         projectName={project.name}
         projectId={project.id}
         onSave={async (content) => {
           setDesignDocContent(content)
           setDesignDocModalOpen(false)
           // In a real app, you would save this to the database
         }}
       />
     </div>
   )
 }

'use client'

import { useEffect, useState } from 'react'
import Link from 'next/link'
import { useParams, useRouter } from 'next/navigation'
import { EditProjectModal } from '@/components/EditProjectModal'
import { DesignDocumentModal } from '@/components/DesignDocumentModal'
import { MarkdownRenderer } from '@/components/MarkdownRenderer'
import { StoriesTab } from '@/components/StoriesTab'
import { NotesTab } from '@/components/NotesTab'
import { ActionsMenu } from '@/components/ActionsMenu'

interface Project {
  id: string
  name: string
  slug: string
  description: string
  ownerId: string
  createdAt: string
  updatedAt: string
}

export default function ProjectDetailPage() {
  const params = useParams()
  const router = useRouter()
  const slug = params.slug as string
  const [project, setProject] = useState<Project | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [editModalOpen, setEditModalOpen] = useState(false)
  const [designDocModalOpen, setDesignDocModalOpen] = useState(false)
  const [activeTab, setActiveTab] = useState<'notes' | 'design-doc' | 'stories'>('notes')
  const [designDocContent, setDesignDocContent] = useState<string>('')
  const [isEditingDesignDoc, setIsEditingDesignDoc] = useState(false)

  useEffect(() => {
    loadProject()
  }, [slug])

  const loadProject = async () => {
    try {
      const response = await fetch('/api/projects')
      if (response.ok) {
        const projects = await response.json()
        const found = projects.find((p: Project) => p.slug === slug)
        if (found) {
          setProject(found)
        } else {
          setError('Project not found')
        }
      }
    } catch (err) {
      setError('Failed to load project')
    } finally {
      setLoading(false)
    }
  }

  const handleDelete = async () => {
    if (!project) return
    if (!confirm('Are you sure you want to delete this project?')) return

    try {
      const response = await fetch(`/api/projects/${project.id}`, {
        method: 'DELETE',
      })
      if (response.ok) {
        router.push('/projects')
      }
    } catch (err) {
      alert('Failed to delete project')
    }
  }

  if (loading) {
    return (
      <div className="text-center py-12">
        <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
        <p className="text-slate-400 mt-2">Loading project...</p>
      </div>
    )
  }

  if (error || !project) {
    return (
      <div className="space-y-6">
        <Link href="/projects" className="text-blue-400 hover:underline">
          ← Back to Projects
        </Link>
        <div className="border border-red-700 rounded-2xl p-8 text-center bg-red-900/30">
          <p className="text-red-400">{error || 'Project not found'}</p>
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-8">
      {/* Header with Actions Menu */}
      <div className="flex justify-between items-start gap-4">
        <div>
          <Link href="/projects" className="text-blue-400 hover:underline mb-4 inline-block">
            ← Back to Projects
          </Link>
          <h1 className="text-4xl font-bold text-white mt-2">{project.name}</h1>
          {project.description && (
            <p className="text-slate-400 mt-2">{project.description}</p>
          )}
        </div>
        <ActionsMenu
          project={project}
          onEdit={() => setEditModalOpen(true)}
          onDelete={handleDelete}
          onGenerateDesignDoc={() => setDesignDocModalOpen(true)}
          onDownloadDesignDoc={() => {
            // Download design doc functionality
          }}
        />
      </div>

      {/* Tabs */}
      <div className="space-y-6">
        <div className="flex gap-4 border-b border-slate-700">
          <button
            onClick={() => setActiveTab('notes')}
            className={`px-6 py-3 font-semibold transition-colors ${
              activeTab === 'notes'
                ? 'text-blue-400 border-b-2 border-blue-400'
                : 'text-slate-400 hover:text-slate-300'
            }`}
          >
             Notes
          </button>
          <button
            onClick={() => setActiveTab('design-doc')}
            className={`px-6 py-3 font-semibold transition-colors ${
              activeTab === 'design-doc'
                ? 'text-blue-400 border-b-2 border-blue-400'
                : 'text-slate-400 hover:text-slate-300'
            }`}
          >
             Design Doc
          </button>
          <button
            onClick={() => setActiveTab('stories')}
            className={`px-6 py-3 font-semibold transition-colors ${
              activeTab === 'stories'
                ? 'text-blue-400 border-b-2 border-blue-400'
                : 'text-slate-400 hover:text-slate-300'
            }`}
          >
             Stories
          </button>
        </div>

        {/* Tab Content */}
        {activeTab === 'notes' && (
          <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6 min-h-96">
            <NotesTab projectId={project.id} />
          </div>
        )}

        {activeTab === 'design-doc' && (
          <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6 min-h-96">
            {designDocContent ? (
              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <h3 className="text-xl font-bold text-white">Project Design Document</h3>
                  <div className="flex gap-2">
                    <button
                      onClick={() => setIsEditingDesignDoc(!isEditingDesignDoc)}
                      className={`px-4 py-2 rounded-lg transition-colors font-medium ${
                        isEditingDesignDoc
                          ? 'bg-green-600 hover:bg-green-700 text-white'
                          : 'bg-slate-700 hover:bg-slate-600 text-white'
                      }`}
                    >
                      {isEditingDesignDoc ? '✓ Done Editing' : '✏️ Edit'}
                    </button>
                    <button
                      onClick={() => setDesignDocModalOpen(true)}
                      className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium"
                    >
                       Regenerate
                    </button>
                  </div>
                </div>

                {isEditingDesignDoc ? (
                  <textarea
                    value={designDocContent}
                    onChange={(e) => setDesignDocContent(e.target.value)}
                    className="w-full h-96 px-4 py-3 bg-slate-900 border border-slate-600 rounded-lg text-white font-mono text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                ) : (
                  <div className="bg-slate-900 border border-slate-700 rounded-lg p-4 overflow-auto max-h-96 text-slate-300 text-sm">
                    <MarkdownRenderer content={designDocContent} />
                  </div>
                )}
              </div>
            ) : (
              <div className="text-center py-8">
                <div className="text-4xl mb-4"></div>
                <h3 className="text-lg font-semibold text-white mb-2">No Design Document</h3>
                <p className="text-slate-400 mb-6">Generate a design document to get started</p>
                <button
                  onClick={() => setDesignDocModalOpen(true)}
                  className="px-6 py-2 bg-gradient-to-r from-purple-600 to-purple-700 text-white font-medium rounded-full hover:from-purple-500 hover:to-purple-600 transition-colors"
                >
                   Generate Design Doc
                </button>
              </div>
            )}
          </div>
        )}

        {activeTab === 'stories' && (
          <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6 min-h-96">
            <StoriesTab
              projectId={project.id}
              designDocContent={designDocContent}
              onStoriesGenerated={(stories) => {
                // Stories generated callback
              }}
            />
          </div>
        )}
      </div>

      {/* Tabs */}
       <EditProjectModal
         isOpen={editModalOpen}
         projectId={project.id}
         projectName={project.name}
         projectDescription={project.description}
         onClose={() => setEditModalOpen(false)}
         onSuccess={() => loadProject()}
       />

       {/* Design Document Modal */}
       <DesignDocumentModal
         isOpen={designDocModalOpen}
         onClose={() => setDesignDocModalOpen(false)}
         projectName={project.name}
         projectId={project.id}
         onSave={async (content) => {
           setDesignDocContent(content)
           setDesignDocModalOpen(false)
           // In a real app, you would save this to the database
         }}
       />
     </div>
   )
 }

'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import { ChevronDown, ChevronRight, Plus, BookOpen, Folder, FileText } from 'lucide-react'

interface ContentItem {
  id: string
  title?: string
  content: string
  order: number
}

interface Subject {
  id: string
  title: string
  slug: string
  order: number
  contentItems?: ContentItem[]
}

interface Topic {
  id: string
  title: string
  slug: string
  order: number
  subjects?: Subject[]
}

interface TreeNodeProps {
  item: Topic | Subject | ContentItem
  type: 'topic' | 'subject' | 'content'
  topicSlug?: string
  expanded: boolean
  onToggle: (id: string) => void
  onAdd: (type: 'topic' | 'subject' | 'content', parentId?: string) => void
  level: number
  activeItem?: string
  onSelect?: (id: string, type: 'topic' | 'subject' | 'content') => void
}

function TreeNode({
  item,
  type,
  topicSlug,
  expanded,
  onToggle,
  onAdd,
  level,
  activeItem,
  onSelect,
}: TreeNodeProps) {
  const hasChildren =
    (type === 'topic' && (item as Topic).subjects && (item as Topic).subjects!.length > 0) ||
    (type === 'subject' && (item as Subject).contentItems && (item as Subject).contentItems!.length > 0)

  const isActive = activeItem === item.id

  const handleSelect = () => {
    if (onSelect) {
      onSelect(item.id, type)
    }
  }

  let href = ''
  if (type === 'topic') {
    href = `/wiki/${(item as Topic).slug}`
  } else if (type === 'subject') {
    href = `/wiki/${topicSlug}/${(item as Subject).slug}`
  }

  const paddingLeft = level * 12

  return (
    <div className="select-none">
      {/* Node Container */}
      <div className="flex items-center gap-0.5 group" style={{ paddingLeft: `${paddingLeft}px` }}>
        {/* Expand/Collapse Button */}
        {hasChildren ? (
          <button
            onClick={() => onToggle(item.id)}
            className="p-0.5 hover:bg-slate-700 rounded transition-colors"
            aria-label={expanded ? 'Collapse' : 'Expand'}
          >
            {expanded ? (
              <ChevronDown className="w-3.5 h-3.5 text-violet-400" />
            ) : (
              <ChevronRight className="w-3.5 h-3.5 text-slate-500" />
            )}
          </button>
        ) : (
          <div className="w-4" />
        )}

        {/* Node Content */}
        <div className="flex-1 flex items-center gap-1.5 min-w-0">
          {/* Icon */}
          {type === 'topic' && <BookOpen className="w-3.5 h-3.5 text-violet-400 flex-shrink-0" />}
          {type === 'subject' && <Folder className="w-3.5 h-3.5 text-blue-400 flex-shrink-0" />}
          {type === 'content' && <FileText className="w-3.5 h-3.5 text-slate-500 flex-shrink-0" />}

          {/* Link or Label */}
          {href ? (
            <Link
              href={href}
              onClick={handleSelect}
              className={`flex-1 px-1 py-0.5 rounded text-xs truncate transition-colors ${
                isActive
                  ? 'bg-violet-600/30 text-violet-300 font-medium'
                  : 'text-slate-300 hover:text-white hover:bg-slate-700/50'
              }`}
            >
              {item.title}
            </Link>
          ) : (
            <span className="flex-1 px-1 py-0.5 rounded text-xs truncate text-slate-300">
              {item.title}
            </span>
          )}
        </div>

        {/* Add Button (appears on hover) */}
        {type !== 'content' && (
          <button
            onClick={() => onAdd(type === 'topic' ? 'subject' : 'content', item.id)}
            className="p-0.5 opacity-0 group-hover:opacity-100 hover:bg-violet-600 rounded transition-all hover:text-white text-slate-400 flex-shrink-0"
            title={`Add ${type === 'topic' ? 'subject' : 'content'}`}
          >
            <Plus className="w-3 h-3" />
          </button>
        )}
      </div>

      {/* Children */}
      {expanded && hasChildren && (
        <div className="space-y-0">
          {type === 'topic' &&
            (item as Topic).subjects?.map((subject) => (
              <TreeNode
                key={subject.id}
                item={subject}
                type="subject"
                topicSlug={(item as Topic).slug}
                expanded={expanded}
                onToggle={onToggle}
                onAdd={onAdd}
                level={level + 1}
                activeItem={activeItem}
                onSelect={onSelect}
              />
            ))}
          {type === 'subject' &&
            (item as Subject).contentItems?.map((content) => (
              <TreeNode
                key={content.id}
                item={content}
                type="content"
                topicSlug={topicSlug}
                expanded={expanded}
                onToggle={onToggle}
                onAdd={onAdd}
                level={level + 1}
                activeItem={activeItem}
                onSelect={onSelect}
              />
            ))}
        </div>
      )}
    </div>
  )
}

interface WikiSidebarProps {
  onItemSelect?: (id: string, type: 'topic' | 'subject' | 'content') => void
  activeItemId?: string
}

export function WikiSidebar({ onItemSelect, activeItemId }: WikiSidebarProps) {
  const [topics, setTopics] = useState<Topic[]>([])
  const [expandedNodes, setExpandedNodes] = useState<Set<string>>(new Set())
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    loadTopics()
  }, [])

  const loadTopics = async () => {
    try {
      const response = await fetch('/api/wiki')
      if (response.ok) {
        const data = await response.json()
        setTopics(data)
      }
    } catch (error) {
      console.error('Failed to load topics:', error)
    } finally {
      setLoading(false)
    }
  }

  const toggleNode = useCallback((id: string) => {
    setExpandedNodes((prev) => {
      const next = new Set(prev)
      if (next.has(id)) {
        next.delete(id)
      } else {
        next.add(id)
      }
      return next
    })
  }, [])

  const handleAdd = useCallback((type: 'topic' | 'subject' | 'content', parentId?: string) => {
    if (type === 'topic') {
      window.location.href = '/wiki'
    } else if (type === 'subject' && parentId) {
      const topic = topics.find((t) => t.id === parentId)
      if (topic) {
        window.location.href = `/wiki/${topic.slug}`
      }
    } else if (type === 'content' && parentId) {
      for (const topic of topics) {
        const subject = topic.subjects?.find((s) => s.id === parentId)
        if (subject) {
          window.location.href = `/wiki/${topic.slug}/${subject.slug}`
          return
        }
      }
    }
  }, [topics])

  if (loading) {
    return (
      <div className="px-4 py-2 text-xs text-slate-400">
        <span className="animate-pulse">Loading wiki...</span>
      </div>
    )
  }

  return (
    <div className="flex flex-col w-full">
      {/* Wiki Header */}
      <div className="px-4 py-3 flex items-center justify-between gap-2">
        <div className="flex items-center gap-2 min-w-0">
          <BookOpen className="w-4 h-4 text-violet-400 flex-shrink-0" />
          <span className="text-sm font-semibold text-white truncate">Wiki</span>
        </div>
        <button
          onClick={() => handleAdd('topic')}
          className="p-1 hover:bg-violet-600 rounded transition-colors text-slate-400 hover:text-white flex-shrink-0"
          title="Add topic"
        >
          <Plus className="w-3.5 h-3.5" />
        </button>
      </div>

      {/* Tree Items */}
      {topics.length === 0 ? (
        <div className="px-4 py-2 text-center">
          <p className="text-xs text-slate-400">No topics</p>
        </div>
      ) : (
        <div className="space-y-0.5 px-2">
          {topics.map((topic) => (
            <TreeNode
              key={topic.id}
              item={topic}
              type="topic"
              expanded={expandedNodes.has(topic.id)}
              onToggle={toggleNode}
              onAdd={handleAdd}
              level={0}
              activeItem={activeItemId}
              onSelect={onItemSelect}
            />
          ))}
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import { ChevronDown, ChevronRight, Plus, BookOpen, Folder, FileText } from 'lucide-react'

interface ContentItem {
  id: string
  title?: string
  content: string
  order: number
}

interface Subject {
  id: string
  title: string
  slug: string
  order: number
  contentItems?: ContentItem[]
}

interface Topic {
  id: string
  title: string
  slug: string
  order: number
  subjects?: Subject[]
}

interface TreeNodeProps {
  item: Topic | Subject | ContentItem
  type: 'topic' | 'subject' | 'content'
  topicSlug?: string
  expanded: boolean
  onToggle: (id: string) => void
  onAdd: (type: 'topic' | 'subject' | 'content', parentId?: string) => void
  level: number
  activeItem?: string
  onSelect?: (id: string, type: 'topic' | 'subject' | 'content') => void
}

function TreeNode({
  item,
  type,
  topicSlug,
  expanded,
  onToggle,
  onAdd,
  level,
  activeItem,
  onSelect,
}: TreeNodeProps) {
  const hasChildren =
    (type === 'topic' && (item as Topic).subjects && (item as Topic).subjects!.length > 0) ||
    (type === 'subject' && (item as Subject).contentItems && (item as Subject).contentItems!.length > 0)

  const isActive = activeItem === item.id

  const handleSelect = () => {
    if (onSelect) {
      onSelect(item.id, type)
    }
  }

  // Get display title - use first 20 chars of content if title is missing for content items
  const getDisplayTitle = () => {
    if (item.title) {
      return item.title
    }
    if (type === 'content' && (item as ContentItem).content) {
      return (item as ContentItem).content.substring(0, 20)
    }
    return 'Untitled'
  }

  let href = ''
  if (type === 'topic') {
    href = `/wiki/${(item as Topic).slug}`
  } else if (type === 'subject') {
    href = `/wiki/${topicSlug}/${(item as Subject).slug}`
  }

  const paddingLeft = level * 12

  return (
    <div className="select-none">
      {/* Node Container */}
      <div className="flex items-center gap-0.5 group" style={{ paddingLeft: `${paddingLeft}px` }}>
        {/* Expand/Collapse Button */}
        {hasChildren ? (
          <button
            onClick={() => onToggle(item.id)}
            className="p-0.5 hover:bg-slate-700 rounded transition-colors"
            aria-label={expanded ? 'Collapse' : 'Expand'}
          >
            {expanded ? (
              <ChevronDown className="w-3.5 h-3.5 text-violet-400" />
            ) : (
              <ChevronRight className="w-3.5 h-3.5 text-slate-500" />
            )}
          </button>
        ) : (
          <div className="w-4" />
        )}

        {/* Node Content */}
        <div className="flex-1 flex items-center gap-1.5 min-w-0">
          {/* Icon */}
          {type === 'topic' && <BookOpen className="w-3.5 h-3.5 text-violet-400 flex-shrink-0" />}
          {type === 'subject' && <Folder className="w-3.5 h-3.5 text-blue-400 flex-shrink-0" />}
          {type === 'content' && <FileText className="w-3.5 h-3.5 text-slate-500 flex-shrink-0" />}

           {/* Link or Label */}
           {href ? (
             <Link
               href={href}
               onClick={handleSelect}
               className={`flex-1 px-1 py-0.5 rounded text-xs truncate transition-colors ${
                 isActive
                   ? 'bg-violet-600/30 text-violet-300 font-medium'
                   : 'text-slate-300 hover:text-white hover:bg-slate-700/50'
               }`}
             >
               {getDisplayTitle()}
             </Link>
           ) : (
             <span className="flex-1 px-1 py-0.5 rounded text-xs truncate text-slate-300">
               {getDisplayTitle()}
             </span>
           )}
        </div>

        {/* Add Button (appears on hover) */}
        {type !== 'content' && (
          <button
            onClick={() => onAdd(type === 'topic' ? 'subject' : 'content', item.id)}
            className="p-0.5 opacity-0 group-hover:opacity-100 hover:bg-violet-600 rounded transition-all hover:text-white text-slate-400 flex-shrink-0"
            title={`Add ${type === 'topic' ? 'subject' : 'content'}`}
          >
            <Plus className="w-3 h-3" />
          </button>
        )}
      </div>

      {/* Children */}
      {expanded && hasChildren && (
        <div className="space-y-0">
          {type === 'topic' &&
            (item as Topic).subjects?.map((subject) => (
              <TreeNode
                key={subject.id}
                item={subject}
                type="subject"
                topicSlug={(item as Topic).slug}
                expanded={expanded}
                onToggle={onToggle}
                onAdd={onAdd}
                level={level + 1}
                activeItem={activeItem}
                onSelect={onSelect}
              />
            ))}
          {type === 'subject' &&
            (item as Subject).contentItems?.map((content) => (
              <TreeNode
                key={content.id}
                item={content}
                type="content"
                topicSlug={topicSlug}
                expanded={expanded}
                onToggle={onToggle}
                onAdd={onAdd}
                level={level + 1}
                activeItem={activeItem}
                onSelect={onSelect}
              />
            ))}
        </div>
      )}
    </div>
  )
}

interface WikiSidebarProps {
  onItemSelect?: (id: string, type: 'topic' | 'subject' | 'content') => void
  activeItemId?: string
}

export function WikiSidebar({ onItemSelect, activeItemId }: WikiSidebarProps) {
  const [topics, setTopics] = useState<Topic[]>([])
  const [expandedNodes, setExpandedNodes] = useState<Set<string>>(new Set())
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    loadTopics()
  }, [])

  const loadTopics = async () => {
    try {
      const response = await fetch('/api/wiki')
      if (response.ok) {
        const data = await response.json()
        setTopics(data)
      }
    } catch (error) {
      console.error('Failed to load topics:', error)
    } finally {
      setLoading(false)
    }
  }

  const toggleNode = useCallback((id: string) => {
    setExpandedNodes((prev) => {
      const next = new Set(prev)
      if (next.has(id)) {
        next.delete(id)
      } else {
        next.add(id)
      }
      return next
    })
  }, [])

  const handleAdd = useCallback((type: 'topic' | 'subject' | 'content', parentId?: string) => {
    if (type === 'topic') {
      window.location.href = '/wiki'
    } else if (type === 'subject' && parentId) {
      const topic = topics.find((t) => t.id === parentId)
      if (topic) {
        window.location.href = `/wiki/${topic.slug}`
      }
    } else if (type === 'content' && parentId) {
      for (const topic of topics) {
        const subject = topic.subjects?.find((s) => s.id === parentId)
        if (subject) {
          window.location.href = `/wiki/${topic.slug}/${subject.slug}`
          return
        }
      }
    }
  }, [topics])

  if (loading) {
    return (
      <div className="px-4 py-2 text-xs text-slate-400">
        <span className="animate-pulse">Loading wiki...</span>
      </div>
    )
  }

  return (
    <div className="flex flex-col w-full">
      {/* Wiki Header */}
      <div className="px-4 py-3 flex items-center justify-between gap-2">
        <div className="flex items-center gap-2 min-w-0">
          <BookOpen className="w-4 h-4 text-violet-400 flex-shrink-0" />
          <span className="text-sm font-semibold text-white truncate">Wiki</span>
        </div>
        <button
          onClick={() => handleAdd('topic')}
          className="p-1 hover:bg-violet-600 rounded transition-colors text-slate-400 hover:text-white flex-shrink-0"
          title="Add topic"
        >
          <Plus className="w-3.5 h-3.5" />
        </button>
      </div>

      {/* Tree Items */}
      {topics.length === 0 ? (
        <div className="px-4 py-2 text-center">
          <p className="text-xs text-slate-400">No topics</p>
        </div>
      ) : (
        <div className="space-y-0.5 px-2">
          {topics.map((topic) => (
            <TreeNode
              key={topic.id}
              item={topic}
              type="topic"
              expanded={expandedNodes.has(topic.id)}
              onToggle={toggleNode}
              onAdd={handleAdd}
              level={0}
              activeItem={activeItemId}
              onSelect={onItemSelect}
            />
          ))}
        </div>
      )}
    </div>
  )
}
